import {
  tokenStorageKey,
  languageStorageKey,
  redirectStorageKey,
} from '@common/constants/localStorageKey'

// 重定向存储url (used by employee login flow in hse-website, kept for shared package compatibility)
export const setRedirectStorage = () => {
  const urlInfo = new URL(window.location.href)
  const url = urlInfo.origin + '/emergency-response'
  const value = encodeURIComponent(url)
  window.sessionStorage.setItem(redirectStorageKey, value)
  return value
}

export const getRedirectStorage = () => {
  let value = window.sessionStorage.getItem(redirectStorageKey) || '/'
  value = decodeURIComponent(value)
  removeRedirectStorage()
  return value
}

export const removeRedirectStorage = () => {
  window.sessionStorage.removeItem(redirectStorageKey)
}

export const redirectToLogin = () => {
  removeToken()
  window.location.replace('/contractor-login')
}

